import ProductCard from "./cart"
import { MyFooter } from './footer';
import { Addtocart } from "./addtocart";
import Card from "./cart";
import Navbar from "./navbar"
import myimage from './images/shoes.jpeg'
import { Link } from "react-router-dom";
import frontimage from './images/banner.webp'
import { Faq } from "./faq";
import { Contactus } from "./contactus";
import { useEffect,useState } from "react";
import axios from 'axios';
import AOS from 'aos';
import 'aos/dist/aos.css'; // Import AOS CSS for default styles

export const Home = () => {
  useEffect(() => {
    AOS.init();
  }, []);
  const [cardData, setCardData] = useState([]);
  const [loading, setLoading] = useState(true); // Track loading state
  const apiUrl = 'https://fakestoreapi.com/products';

  useEffect(() => {
    axios.get(apiUrl)
      .then((response) => {
        setCardData(response.data);
        setLoading(false); // Set loading to false when data is fetched
      })
      .catch((error) => {
        console.error('Error fetching data:', error);
        setLoading(false);  
      });
  }, []);

  return (
    <>
      <Navbar />
      <div className="bg-gray-100 py-16 md:flex items-center mygradiantcontent">
        <div data-aos="fade-right" className="md:w-1/2 p-4 md:p-8 text-gray-900">
          <h1 className="text-4xl font-semibold  ">Discover the Latest in Fashion</h1>
          <p className="text-lg   mt-4 font-semibold">Explore a World of Style for Men, Women, and Kids</p>
          <div className="mt-6">
            <h2 className="text-xl font-semibold">Our Mission:</h2>
            <p className="mt-2 font-semibold  ">
              At our e-commerce store, we are dedicated to bringing you the latest trends and top-quality clothing for the entire family. From stylish men's collections to elegant women's fashion and adorable kids' clothing, we've got you covered.
            </p>
          </div>
          <div className="mt-4">
            <a href="#featured_product" className="bg-blue-500 text-white hover:bg-blue-600 px-4 py-2 mt-2 inline-block">Buy Now</a>
          </div>
        </div>
        <div  data-aos="fade-left" className="md:w-1/2   ">
          <a href="#">
            <img className="w-full h-auto p-8 text-center rounded-t-lg transform hover:scale-110 transition-transform duration-300 ease-in-out" src={frontimage} alt="product image" />
          </a>
        </div>
      </div>


      {loading ? (

       <>
         <div className="container mx-auto flex flex-col items-center justify-center h-screen">
           <div role="status"  >
           <svg aria-hidden="true" class="inline custom-svg-size mr-2 text-gray-200 animate-spin dark:text-gray-600 fill-blue-600" viewBox="0 0 100 101" fill="none" xmlns="http://www.w3.org/2000/svg">
               <path d="M100 50.5908C100 78.2051 77.6142 100.591 50 100.591C22.3858 100.591 0 78.2051 0 50.5908C0 22.9766 22.3858 0.59082 50 0.59082C77.6142 0.59082 100 22.9766 100 50.5908ZM9.08144 50.5908C9.08144 73.1895 27.4013 91.5094 50 91.5094C72.5987 91.5094 90.9186 73.1895 90.9186 50.5908C90.9186 27.9921 72.5987 9.67226 50 9.67226C27.4013 9.67226 9.08144 27.9921 9.08144 50.5908Z" fill="currentColor" />
               <path d="M93.9676 39.0409C96.393 38.4038 97.8624 35.9116 97.0079 33.5539C95.2932 28.8227 92.871 24.3692 89.8167 20.348C85.8452 15.1192 80.8826 10.7238 75.2124 7.41289C69.5422 4.10194 63.2754 1.94025 56.7698 1.05124C51.7666 0.367541 46.6976 0.446843 41.7345 1.27873C39.2613 1.69328 37.813 4.19778 38.4501 6.62326C39.0873 9.04874 41.5694 10.4717 44.0505 10.1071C47.8511 9.54855 51.7191 9.52689 55.5402 10.0491C60.8642 10.7766 65.9928 12.5457 70.6331 15.2552C75.2735 17.9648 79.3347 21.5619 82.5849 25.841C84.9175 28.9121 86.7997 32.2913 88.1811 35.8758C89.083 38.2158 91.5421 39.6781 93.9676 39.0409Z" fill="currentFill" />
             </svg>

           </div>

         </div>

       </>
     ) : (

      <div className="App" id="featured_product">
        <h1 className="text-2xl md:text-3xl font-bold m-4">Featured product</h1>
        <div className="flex flex-wrap -mx-4">
          {cardData.map((card) => (
            <div key={card.id} className="w-full sm:w-1/2 md:w-1/3 p-4">
              <ProductCard imageUrl={card.image} title={card.title} price={card.price} />
            </div>
          ))}
        </div>
      </div>
     )} 
      <MyFooter />
    </>
  );
};
